func  (this *KucoinCore) ParseWsTrade(trade any, optionalArgs ...any) any  {
    //
    // /spotMarket/tradeOrders
    //
    //     {
    //         "symbol": "KCS-USDT",
    //         "orderType": "limit",
    //         "side": "sell",
    //         "orderId": "5efab07953bdea00089965fa",
    //         "liquidity": "taker",
    //         "type": "match",
    //         "feeType": "takerFee",
    //         "orderTime": 1670329987026,
    //         "size": "0.1",
    //         "filledSize": "0.1",
    //         "price": "0.938",
    //         "matchPrice": "0.96738",
    //         "matchSize": "0.1",
    //         "tradeId": "5efab07a4ee4c7000a82d6d9",
    //         "clientOid": "1593487481000313",
    //         "remainSize": "0",
    //         "status": "match",
    //         "ts": 1670329987311000000
    //     }
    //
    // /spot/tradeFills
    //
    //    {
    //        "fee": 0.00262148,
    //        "feeCurrency": "USDT",
    //        "feeRate": 0.001,
    //        "orderId": "62417436b29df8000183df2f",
    //        "orderType": "market",
    //        "price": 131.074,
    //        "side": "sell",
    //        "size": 0.02,
    //        "symbol": "LTC-USDT",
    //        "time": "1648456758734571745",
    //        "tradeId": "624174362e113d2f467b3043"
    //    }
    //
    market := ccxt.GetArg(optionalArgs, 0, nil)
    _ = market
    var marketId any = this.SafeString(trade, "symbol")
    market = this.SafeMarket(marketId, market, "-")
    var symbol any = ccxt.GetValue(market, "symbol")
    var typeVar any = this.SafeString(trade, "orderType")
    var side any = this.SafeString(trade, "side")
    var tradeId any = this.SafeString(trade, "tradeId")
    var price any = this.SafeString(trade, "matchPrice")
    var amount any = this.SafeString(trade, "matchSize")
    if ccxt.IsTrue(ccxt.IsEqual(price, nil)) {
        // /spot/tradeFills
        price = this.SafeString(trade, "price")
        amount = this.SafeString(trade, "size")
    }
    var order any = this.SafeString(trade, "orderId")
    var timestamp any = this.SafeIntegerProduct2(trade, "ts", "time", 0.000001)
    var feeCurrency any = ccxt.GetValue(market, "quote")
    var feeRate any = this.SafeString(trade, "feeRate")
    var feeCost any = this.SafeString(trade, "fee")
    return this.SafeTrade(map[string]any {
        "info": trade,
        "timestamp": timestamp,
        "datetime": this.Iso8601(timestamp),
        "symbol": symbol,
        "id": tradeId,
        "order": order,
        "type": typeVar,
        "takerOrMaker": this.SafeString(trade, "liquidity"),
        "side": side,
        "price": price,
        "amount": amount,
        "cost": nil,
        "fee": map[string]any {
            "cost": feeCost,
            "rate": feeRate,
            "currency": feeCurrency,
        },
    }, market)
}
